-- Modify "finance_facts" table
ALTER TABLE "finance_facts" ADD CONSTRAINT "finance_facts_collection_type_allowed" CHECK ((collection_type IS NULL) OR ((collection_type)::text = ANY ((ARRAY['ADVANCE_RECEIPT'::character varying, 'ACCOUNTS_RECEIVABLE'::character varying])::text[]))), ADD CONSTRAINT "finance_facts_invoice_category_allowed" CHECK ((invoice_category IS NULL) OR ((invoice_category)::text = ANY ((ARRAY['NONE'::character varying, 'EXPORT_GENERAL'::character varying, 'VAT_GENERAL_1'::character varying, 'VAT_SPECIAL_3'::character varying, 'VAT_SPECIAL_13'::character varying])::text[]))), ADD CONSTRAINT "finance_facts_payment_term_allowed" CHECK ((payment_term IS NULL) OR ((payment_term)::text = ANY ((ARRAY['CASH_ON_SHIPMENT'::character varying, 'EOM_30'::character varying, 'EOM_45'::character varying])::text[]))), ADD CONSTRAINT "finance_facts_payment_term_days_check" CHECK ((payment_term_days IS NULL) OR (payment_term_days >= 0)), ADD COLUMN "collection_type" character varying NULL, ADD COLUMN "payment_term" character varying NULL, ADD COLUMN "payment_term_days" bigint NULL, ADD COLUMN "invoice_category" character varying NULL;
